import type { FilmClubFormData, FilmClubSubmissionResponse } from '../types/film-club';

const submitFilmClub = async (data: FilmClubFormData): Promise<FilmClubSubmissionResponse> => {
  try {
    // Validate required fields
    if (!data.fullName || !data.email || !data.company || !data.role || !data.linkedin) {
      throw new Error('Missing required fields: fullName, email, company, role, and linkedin are required');
    }

    // Validate email format
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(data.email)) {
      throw new Error('Please provide a valid email address');
    }

    // Validate LinkedIn URL format
    if (!data.linkedin.includes('linkedin.com')) {
      throw new Error('Please provide a valid LinkedIn URL');
    }

    // Submit to Airtable via API
    const response = await fetch(
      `https://api.airtable.com/v0/${import.meta.env.PUBLIC_AIRTABLE_BASE_ID}/Form%20Responses`,
      {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${import.meta.env.PUBLIC_AIRTABLE_API_TOKEN}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          records: [
            {
              fields: {
                'Name': data.fullName.trim(),
                'Email': data.email.trim().toLowerCase(),
                'Company': data.company.trim(),
                'Role': data.role.trim(),
                'LinkedIn Profile': data.linkedin.trim(),
                'Sponsorship Interest': data.interestedInSponsoring,
                'Submitted At': new Date().toISOString()
              }
            }
          ]
        })
      }
    );

    if (!response.ok) {
      const errorData = await response.json();
      throw new Error(errorData.error?.message || 'Failed to submit to Airtable');
    }

    const result = await response.json();

    return {
      code: 'SUCCESS',
      id: result.records[0].id
    };
  } catch (error) {
    if (error instanceof Error) {
      throw new Error(error.message);
    }
    throw new Error('Something went wrong. Please try again.');
  }
};

export default submitFilmClub;
